import type { ReactNode } from 'react';

/**
 * GetToken接口
 */
export interface IGetToken {
    getToken(accessToken: string): Promise<any>;
    getAllVendorToken(accessToken: string): Promise<any>;
}

/**
 * JSLoader 返回函数
 */
export interface IjsLoaderCallback {
    (options: SPOpts | IpreSign): void | string;

}

/**
 * 回调参数
 */

export interface ICallBackOpts {
    code: number,
    requestId: string,
    msg?: string,
    content?: any,
    spToken?: string
}

/**
 * 移动preSign回调参数
 */

export interface IpreSignnCallBackOpts {
    code: number,
    msg?: string,
    content?: any,
    accessToken?: string
}

/**
 * 回调函数
 */
export interface IcallBackFun {
    (res: ICallBackOpts | string): void;
}

/**
 * checkAuth的响应参数
 */
export interface ITokenParamsType {
    appId: '',
    vender: string,
    reqTimeStamp?: string,
    paramKey?: string,
    paramStr?: string,
    sign: string,
    bizType?: number,
    mark?: string,
    cmTraceId?: string
}

/**
 * checkAuthAvailable 验证的入参
 */
export interface IcheckAuthOpts {
    accessToken: string, //鉴权密钥
    jwtToken: string,
    phoneNumber?: string, // 手机号码
    timeout?: number,
    success: IcallBackFun, //回调
    error: IcallBackFun
}

/**
 * checkAuthAvailable 验证的入参
 */
export interface IcheckAuthParams {
    accessToken: string, //鉴权密钥
    jwtToken: string,
    phoneNumber?: string,  // 手机号码
    bizType?: number, // 用来区分一键登录&号码校验鉴权的业务类型
    version?: string
}

/**
 * getVerifyToken的入参
 */
export interface IgetVerifyOpts {
    timeout?: number,
    success: IcallBackFun, //回调
    error: IcallBackFun
}

/**
 * 运营商获取token参数
 */
export interface SPOpts {
    params: CMParams | CUParams | CTParams, //获取token入参
    success: IcallBackFun, //成功回调
    error: IcallBackFun, //失败回调
    accessToken: string,
    debuggerMode?: boolean
}


/**
 * 联通初始化传参
 */

export interface CUParams {
    ts: string, //客户端发起请求的时间戳；需对时间进行格式化，格式为yyyyMMddHHmmssSSS
    appKey: string, //接入ID
    authenticator: string, //客户端发起请求的鉴权密钥
    signType: string
}

