/**
 * 移动获取token参数
 */
export interface CMParams {
    version: string, //接口版本号 （必填）
    appId: string, //应用Id （必填）注册时分发
    sign: string, //RSA加密后的sign（必填）
    timestamp?: string,
    openType: string, //移动取号接口填写1，三网取号接口填写0 （必填，联调时必须填写为1）
    expandParams?: string, //扩展参数  格式：参数名=值  多个时使用 | 分割（选填，联调环境只能模拟取号，联调时需填写phoneNum=188185*****  手机号可以随便填写，生产可不填）
    isTest: string,//是否启用测试线地址（传0时为启用，不为0或者不传时为不启用）
}


/**
 * 电信token参数
 */
export interface CTParams {
    appId: string, //应用Id （必填）
    clientType: string, // 客户端类型 Android-30100 ，IOS-30300，H5-20200 WEB-10010
    format: string, // 返回格式
    sign: string, //RSA加密后的sign（必填）
    version: string, //接口版本号 （必填）
    paramKey: string, // 加密后的公钥
    paramStr: string //不公开请求的参数
}

/**
 * 移动preSign传参
 */
export interface IpreSign {
    appId: string,
    version: string,
    callback: IcallBackFun
}

export interface ICarrierInfo {
    carrierTraceId: any,
    carrierSdkCode: number,
    carrierRespCode?: number
    carrierSdkMsg?: string
}

export interface AllVendorCarrierInfo {
    cmccCarrierTraceId?: any, // 移动接口请求失败
    cmccCarrierSdkCode?: number,
    cmccCarrierSdkMsg?: string, // 移动运营商返回的msg
    cmccCarrierRespCode?: number,
    ctccCarrierTraceId?: any, // 电信接口请求失败
    ctccCarrierSdkCode?: number,
    ctccCarrierSdkMsg?: string, // 电信运营商返回的msg
    ctccCarrierRespCode?: number,
    cuccCarrierTraceId?: any, // 联通接口请求失败
    cuccCarrierSdkCode?: number
    cuccCarrierSdkMsg?: string, // 联通运营商返回的msg
    cuccCarrierRespCode?: number
}

export interface ICMResData {
    carrierTraceId: string,
    carrierSdkCode: number,
    carrierRespCode?: number
    carrierMsg?: string
}

export interface IConfigParam {
    isDemoted?: boolean,
    is_limited?: any,
    isLimited?: boolean, // 限流
    msg?: string,
    limitTime?: number,
    limitCount?: number,
    reqCount?: number,
    lastReqTime?: number
}


export interface ICarrierResp {
    code: number,
    msg: string,
    vender?: string,
    carrier?: ICarrierInfo,
    content: any,
    requestId?: string,
    clearInput?: Function,
    focusOn?: Function,
    setMessage?: Function
}

export interface IConfigData{
    sdkVersion: string, //sdk版本
    osType: string,
    originId: string,
    businessType: string,
    browserId: string,
    browserVersion: string,
    osId: string,
    osVersion: string,
    vendorId?: string
}

// ---------------  一键登录类型  ---------------------

/**
 * getLoginToken的入参
 */
 export interface IgetLoginOpts {
    timeout?: number,
    authPageOption: any,
    success: Function, //回调
    error: Function,
    watch?(status: number, netType: string, data?: any): void;
    protocolPageWatch?(status: number, netType: string, data?: any): void;
    privacyAlertWatch?(status: number, netType: string, data?: any): void;
    previewPrivacyWatch?(status: number, netType: string, data?: any): void;
}

export interface CMLoginParams {
    version: string, // 接口版本号（必填）
    appId: string, // 应用Id（必填）
    sign: string, // 加密后的sign（必填）。sign生成规则： MD5(appId +businessType + msgId + timestamp + traceId + version+appkey)注：msgID要和traceID保持一致，此处sign与token校验接口sign的生成规则不同
    traceId: string, // 业务方生成唯一标识
    timestamp: string, // 请求消息发送的系统时间，精确到毫秒，共17位，格式：20121227180001165
    openType: string, // 取号类型
    authPageOption?: PageOption, // 可配置ui参数
    watch?(status: number, netType: string, data?: any): void;
    protocolPageWatch?(status: number, netType: string, data?: any): void;
    privacyAlertWatch?(status: number, netType: string, data?: any): void;
    previewPrivacyWatch?(status: number, netType: string, data?: any): void;
}

// 自定义协议前置页面配置
export interface IProtocolOption {
    mount: string, // 容器节点Id
    btnText?: string, // 按钮文案
    agreeSymbol?: string, // 协议分割符
    privacyOne?: [string, string], // 隐私协议一
    privacyTwo?: [string, string], // 隐私协议二
    tips?: string, // 按钮标题tips
    privacyVenderIndex: number,
    vendorPrivacyPrefix?: string, // 设置运营商协议前缀符号，只能设置一个字符，且只能设置<>、()、《》、【】、『』、[]、（）中的一个。
    vendorPrivacySuffix?: string, // 设置运营商协议后缀符号，只能设置一个字符，且只能设置<>、()、《》、【】、『』、[]、（）中的一个。
    privacyBefore?:string, // 设置开发者隐私条款前置自定义文案。
    privacyEnd?:string // 设置开发者隐私条款前置自定义文案。
    privacyCheckedImg?: HTMLImageElement, // 选中时内部的图片
    privacyCheckedUrl?: string, // 协议选中时内部的图片的url
    privacyUnCheckedUrl?:  string, // 协议未选中时内部的图片的url
}

export interface IPrivacyAlertConfig {
    title?: string,
    btnText?: string,
    privacyAlertIsNeedAutoLogin?: boolean, // 设置二次隐私协议弹窗点击按钮是否需要执行登录
    privacyAlertMaskIsNeedShow?: boolean,
    privacyAlertIsDialog?: boolean,
    isLoginShowPrivacyAlert?: string, // 点击登录按钮是否弹出二次隐私协议弹窗，设置为true则未同意协议时弹出此弹窗
    privacyAlertLoginText?: string
    closeUrl?: string
}

export interface PageOption {
    mount?: string,
    navText?: string, // 按钮文案
    navBackImg?: string, // 导航栏返回按钮图片的src链接
    isHideLogo?: boolean, // logo是否隐藏
    subtitle?: string, // 副标题
    logoImg?: string, // logo图片设置
    btnText?: string, // 按钮文案
    isShowProtocolDesc?: boolean,
    agreeSymbol?: string,
    privacyVenderIndex: number,
    vendorPrivacyPrefix?: string, // 设置运营商协议前缀符号，只能设置一个字符，且只能设置<>、()、《》、【】、『』、[]、（）中的一个。
    vendorPrivacySuffix?: string, // 设置运营商协议后缀符号，只能设置一个字符，且只能设置<>、()、《》、【】、『』、[]、（）中的一个。
    privacyBefore?:string, // 设置开发者隐私条款前置自定义文案。
    privacyEnd?:string, // 设置开发者隐私条款前置自定义文案。
    numberLabel?: string,
    privacyCheckedImg?: HTMLImageElement,
    privacyCheckedUrl?: string, // 协议选中时内部的图片的url
    privacyUnCheckedUrl?:  string, // 协议未选中时内部的图片的url
    privacyOne?: [string, string], // 自定义协议1,格式['name',url]
    privacyTwo?: [string, string], // 自定义协议2,格式['name',url]
    privacyAlertIsNeedShow?:boolean, // 设置二次隐私协议弹窗是否显示, 如果设置为false则不展示弹窗，点击协议连接跳转至新tab
    privacyAlertConfig: IPrivacyAlertConfig, // 二次弹窗配置 
    showCustomView?: boolean, // 是否展示自定义控件
    isFocus?: boolean, // 是否自定聚焦 默认为否 如果为是则聚焦第一个输入框
    customView?: { // 添加此属性必须设置 showCustomView 为true，对象形式 {element:'自定义节点',style:'自定义样式',js:'自定义交互'}
        element: string,
        style: string,
        js: string
    }
    isDialog?: boolean, // 是否弹窗样式
    manualClose: boolean, // 是否手动控制关闭授权页面/弹窗
    isPrePageType?: boolean, // 是否显示预授权页面
    prePageTypeOption?: IProtocolOption,
    isShowExtraBtn?: boolean,
    extraBtn?: HTMLElement,
    isShowPreviewPrivacy?: boolean,
    previewPrivacyOption?: {
      title: string,
      MaskIsNeedShow?: boolean,
      IsNeedAutoLogin?: boolean,
      closeUrl?: string
    }
}

export interface CTLoginParams {
    debug?: boolean, // 调试模式,调用的所有api的返回值会在客户端alert出来，在pc端打印出来。
    btnId?: string, // 获取accessCode按钮标签id
    appId: string, // 应用Id（必填）
    sign: string,
    isNoUI: boolean, // 选填，为 true 时，为无界面版
    timeout: number, // 配置接口超时时间设置，单位为毫秒(v1.43 新增)
    authPageOption?: PageOption, // 可配置ui参数
    watch?(status: number, netType: string, data?: any): void;
    protocolPageWatch?(status: number, netType: string, data?: any): void;
    privacyAlertWatch?(status: number, netType: string, data?: any): void;
    previewPrivacyWatch?(status: number, netType: string, data?: any): void;
    getSignParams?(res: object): any,
    ready?(res: object): any, // 预判断成功回调
    success?(res: object): any, // 成功回调
    error?(res: object): any, // 错误回调
}

export interface CULoginParams {
    ts: string, //客户端发起请求的时间戳；需对时间进行格式化，格式为yyyyMMddHHmmssSSS
    appKey: string, //接入ID
    authenticator: string, //客户端发起请求的鉴权密钥
    signType: string
    authPageOption?: PageOption, // 可配置ui参数
    watch?(status: number, netType: string, data?: any): void;
    protocolPageWatch?(status: number, netType: string, data?: any): void;
    privacyAlertWatch?(status: number, netType: string, data?: any): void;
    previewPrivacyWatch?(status: number, netType: string, data?: any): void;
}

export interface IPageSwitchOpt {
    createLoginPage: Function,
    closeLoginPage: Function
}

export interface ITabItem {
    title: ReactNode,
    key: string,
    content: ReactNode
}
